import pika
import time
import json
import threading

# Configuration
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
QUEUE_NAME = 'task_queue'

# Publisher
def publisher(num_tasks):
    connection = None
    try:
        connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT)
        )
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        print(f"Publisher connected to RabbitMQ at {RABBITMQ_HOST}:{RABBITMQ_PORT}")
        print(f"Publisher declared queue: {QUEUE_NAME}")

        for i in range(1, num_tasks + 1):
            task_id = f"task_{i}"
            task_data = {
                'task_id': task_id,
                'description': f"Process data for {task_id}",
                'timestamp': time.time()
            }
            message_body = json.dumps(task_data)

            channel.basic_publish(
                exchange='',
                routing_key=QUEUE_NAME,
                body=message_body,
                properties=pika.BasicProperties(
                    delivery_mode=pika.spec.PERSISTENT_DELIVERY_MODE
                )
            )
            print(f" [x] Sent '{task_id}'")
            time.sleep(0.5) # Simulate work

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Publisher: Failed to connect to RabbitMQ: {e}")
    except Exception as e:
        print(f"Publisher: An error occurred: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Publisher connection closed.")

# Consumer
def consumer():
    connection = None
    try:
        connection = pika.BlockingConnection(
            pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT)
        )
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        print(f"Consumer connected to RabbitMQ at {RABBITMQ_HOST}:{RABBITMQ_PORT}")
        print(f"Consumer declared queue: {QUEUE_NAME}")

        # Ensure only one task is dispatched at a time to a consumer
        channel.basic_qos(prefetch_count=1)

        def callback(ch, method, properties, body):
            task_data = json.loads(body)
            task_id = task_data.get('task_id', 'N/A')
            description = task_data.get('description', 'N/A')
            print(f" [x] Received '{task_id}': {description}")

            # Simulate work
            processing_time = len(description) % 5 + 1 # Simulate variable work
            time.sleep(processing_time)

            print(f" [x] Done processing '{task_id}'")
            ch.basic_ack(delivery_tag=method.delivery_tag)

        channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

        print(' [*] Waiting for messages. To exit press CTRL+C')
        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Consumer: Failed to connect to RabbitMQ: {e}")
    except KeyboardInterrupt:
        print("Consumer: Exiting due to KeyboardInterrupt.")
    except Exception as e:
        print(f"Consumer: An error occurred: {e}")
    finally:
        if connection and connection.is_open:
            connection.close()
            print("Consumer connection closed.")

if __name__ == "__main__":
    # Start consumer in a separate thread
    consumer_thread = threading.Thread(target=consumer)
    consumer_thread.daemon = True # Allow main program to exit even if consumer is still running
    consumer_thread.start()

    # Give consumer a moment to establish connection
    time.sleep(2)

    # Start publisher in the main thread
    publisher(num_tasks=10)

    # Optionally wait for the consumer to finish (if it were not daemon)
    # In this setup, publisher sends messages and exits, consumer continues
    # until interrupted or connection closes.
    # For a clean exit of consumer when publisher finishes,
    # more sophisticated shutdown logic would be needed.
    print("\nPublisher has finished sending messages.")
    print("Consumer is still running and waiting for new messages (or until interrupted).")
    # Keep the main thread alive so daemon consumer thread can run
    try:
        while True:
            time.sleep(1)
    except KeyboardInterrupt:
        print("Main program exiting.")